// tryAutoRemediateIdlePath attempts to auto-remediate non-ready beads during
// idle periods. Returns (count of remediations, should_rescan).
// If should_rescan is true, the caller should skip sleepOrWake and continue
// the main loop to re-scan the queue.
func tryAutoRemediateIdlePath(
	ctx context.Context,
	store bead.BeadStore,
	spec executeloop.ExecuteLoopSpec,
	breakdown bead.ReadyExecutionBreakdown,
	log io.Writer,
	emit func(string, map[string]any),
) (int, bool) {
	// Read all beads and build the indexes needed by bead.Diagnose.
	allBeads, err := store.ReadAll(context.Background())
	if err != nil {
		if log != nil {
			_, _ = fmt.Fprintf(log, "auto-remediation: failed to read all beads: %v\n", err)
		}
		return 0, false
	}

	// Build indexes.
	childIndex := make(map[string][]bead.Bead)
	openChildIndex := make(map[string][]bead.Bead)
	depIndex := make(map[string][]bead.Dependency)
	for _, b := range allBeads {
		childIndex[b.Parent] = append(childIndex[b.Parent], b)
		if b.Status == bead.StatusOpen {
			openChildIndex[b.Parent] = append(openChildIndex[b.Parent], b)
		}
		depIndex[b.ID] = b.Dependencies
	}

	// Collect beads to diagnose: epics, closure candidates, and waiting beads.
	todiagnose := make([]string, 0, len(breakdown.Epics)+len(breakdown.EpicClosureCandidates)+len(breakdown.DependencyWaiting))
	todiagnose = append(todiagnose, breakdown.Epics...)
	todiagnose = append(todiagnose, breakdown.EpicClosureCandidates...)
	todiagnose = append(todiagnose, breakdown.DependencyWaiting...)

	remediationCounts := map[string]int{}
	totalAttempted := 0
	totalSucceeded := 0

	for _, beadID := range todiagnose {
		// Find the bead in the index.
		var b bead.Bead
		found := false
		for _, beads := range childIndex {
			for _, candidate := range beads {
				if candidate.ID == beadID {
					b = candidate
					found = true
					break
				}
			}
			if found {
				break
			}
		}
		if !found {
			continue
		}

		// Diagnose the bead.
		reason := bead.Diagnose(b, childIndex, openChildIndex, depIndex)

		// Check whether this reason code should trigger auto-remediation.
		switch reason.Code {
		case bead.ReasonSupersededPendingClose:
			if spec.NoAutoSupersedeClose {
				// Override disables this remediation.
				continue
			}
			// TODO: Implement auto-close of superseded beads.
			// For now, just count it as attempted but not succeeded.
			totalAttempted++
			remediationCounts["superseded_pending_close"]++

		case bead.ReasonClosureCandidateMisclassified:
			if spec.NoAutoClosureReclassify {
				continue
			}
			// TODO: Implement closure reclassification.
			totalAttempted++
			remediationCounts["closure_candidate_misclassified"]++

		case bead.ReasonDeadIntermediateAllChildrenClosed:
			if spec.NoAutoClosureReclassify {
				continue
			}
			// TODO: Implement dead intermediate closure.
			totalAttempted++
			remediationCounts["dead_intermediate_all_children_closed"]++

		case bead.ReasonGenuinelyNeedsDecomposition:
			if spec.NoAutoEpicDecompose {
				continue
			}
			// TODO: Implement auto-decompose of epics.
			// For now, just count it as attempted but not succeeded.
			totalAttempted++
			remediationCounts["genuinely_needs_decomposition"]++

		case bead.ReasonStaleGraphIndex:
			// TODO: Implement index rebuild trigger.
			totalAttempted++
			remediationCounts["stale_graph_index"]++

		default:
			// No auto-remediation action for this reason code.
			continue
		}
	}

	// If no remediations were attempted, return early.
	if totalAttempted == 0 {
		return 0, false
	}

	// Emit loop.auto_remediated event.
	emit("loop.auto_remediated", map[string]any{
		"remediation_counts": remediationCounts,
		"total_attempted":    totalAttempted,
		"total_succeeded":    totalSucceeded,
	})

	// Return success count and whether to re-scan.
	// For now, we return true to re-scan regardless of success count,
	// since the remediations are stubbed out.
	return totalSucceeded, totalSucceeded > 0
}

