// TestWorkIdle_AutoRemediatesAndRescansWithoutSleep tests that idle-path
// auto-remediation identifies and counts problematic beads without sleeping
// when at least one remediation succeeds.
func TestWorkIdle_AutoRemediatesAndRescansWithoutSleep(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	// Create a mislabeled closure-candidate epic (all children closed).
	epic := &bead.Bead{
		ID:        "ddx-epic-1",
		Title:     "Epic with all children closed",
		IssueType: "epic",
		Status:    bead.StatusOpen,
	}
	require.NoError(t, store.Create(epic))

	// Create children and close them.
	child1 := &bead.Bead{
		ID:     "ddx-child-1",
		Title:  "Child 1",
		Parent: epic.ID,
		Status: bead.StatusClosed,
	}
	require.NoError(t, store.Create(child1))

	child2 := &bead.Bead{
		ID:     "ddx-child-2",
		Title:  "Child 2",
		Parent: epic.ID,
		Status: bead.StatusClosed,
	}
	require.NoError(t, store.Create(child2))

	// Create a superseded bead.
	superseded := &bead.Bead{
		ID:    "ddx-superseded-1",
		Title: "Superseded bead",
		Extra: map[string]interface{}{
			"lifecycle": map[string]interface{}{
				"superseded_by": "ddx-superseding-1",
			},
		},
		Status: bead.StatusOpen,
	}
	require.NoError(t, store.Create(superseded))

	// Create the superseding bead (closed).
	superseding := &bead.Bead{
		ID:     "ddx-superseding-1",
		Title:  "Superseding bead",
		Status: bead.StatusClosed,
	}
	require.NoError(t, store.Create(superseding))

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			// Should not be called in this test (idle queue).
			return ExecuteBeadReport{
				BeadID: beadID,
				Status: ExecuteBeadStatusSuccess,
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker-idle"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once: true,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	// Should have detected the idle state and auto-remediated.
	require.True(t, result.NoReadyWork, "queue should be idle")
	require.Greater(t, len(result.Results), 0, "should have attempted auto-remediations")
}

